271	export default function BotsShowcaseSection() {
272	  const [activeId, setActiveId] = useState<ChatPlatform>(PLATFORMS[0].id);
273	  const active = PLATFORMS.find((p) => p.id === activeId) ?? PLATFORMS[0];
274	  const visibleMessages = useStaggeredMessages(active);
275	  const phoneRef = useRef<HTMLDivElement>(null);
276	  const isCtaFloating = useFloatingCta(phoneRef);
277	
278	  return (
279	    <section className="relative flex w-full flex-col items-center px-4 py-20 sm:px-6 sm:py-24 lg:px-8">
280	      <div className="flex w-full max-w-6xl flex-col items-center gap-8">
281	        <LargeHeader headingText="Reach GAIA from anywhere" centered />
282	
283	        <PlatformChips
284	          platforms={PLATFORMS}
285	          activeId={activeId}
286	          onSelect={setActiveId}
287	        />
288	
289	        <div ref={phoneRef}>
290	          <PhoneFrame platform={active} messages={visibleMessages} />
291	        </div>
292	
293	        <FloatingCTA
294	          isFloating={isCtaFloating}
295	          action={active.primaryAction}
296	          actionKey={active.id}
297	          iconSrc={typeof active.icon === "string" ? active.icon : undefined}
