305	function FloatingCTA({
306	  isFloating,
307	  action,
308	  actionKey,
309	  iconSrc,
310	  comingSoon,
311	}: {
312	  isFloating: boolean;
313	  action: ActionLink;
314	  actionKey: string;
315	  iconSrc: string | undefined;
316	  comingSoon?: boolean;
317	}) {
318	  // Reserve the static-flow slot so the layout never jumps when the button
319	  // pops out of the flow into a fixed position. The CTA is rendered twice:
320	  //   - In flow, invisible while floating (reserves space)
321	  //   - Fixed at the bottom while floating, fades in via opacity only
322	  return (
323	    <div className="relative flex w-full justify-center pt-2">
324	      <div
325	        aria-hidden={isFloating}
326	        className={isFloating ? "pointer-events-none opacity-0" : "opacity-100"}
327	      >
328	        <PlatformCTASwitcher
329	          actionKey={actionKey}
330	          action={action}
331	          iconSrc={iconSrc}
332	          comingSoon={comingSoon}
333	        />
334	      </div>
335	
336	      <AnimatePresence initial={false}>
337	        {isFloating && (
338	          <m.div
339	            key="floating"
340	            initial={{ opacity: 0 }}
341	            animate={{ opacity: 1 }}
342	            exit={{ opacity: 0 }}
343	            transition={{ duration: 0.18, ease: "easeOut" }}
344	            className="pointer-events-none fixed inset-x-0 bottom-6 z-[1001] flex justify-center px-4"
345	          >
346	            <div className="pointer-events-auto">
347	              <PlatformCTASwitcher
348	                actionKey={actionKey}
349	                action={action}
350	                iconSrc={iconSrc}
351	                comingSoon={comingSoon}
352	              />
353	            </div>
354	          </m.div>
355	        )}
356	      </AnimatePresence>
357	    </div>
358	  );
359	}
