376	        initial={{ opacity: 0, y: 4 }}
377	        animate={{ opacity: 1, y: 0 }}
378	        exit={{ opacity: 0, y: -4 }}
379	        transition={{ duration: 0.18, ease: "easeOut" }}
380	      >
381	        <PrimaryCTA action={action} iconSrc={iconSrc} comingSoon={comingSoon} />
382	      </m.div>
383	    </AnimatePresence>
384	  );
