387	function useFloatingCta(
388	  phoneRef: React.RefObject<HTMLDivElement | null>,
389	): boolean {
390	  const [floating, setFloating] = useState(false);
391	
392	  useEffect(() => {
393	    const phone = phoneRef.current;
394	    if (!phone) return;
395	
396	    const update = (): void => {
397	      const phoneRect = phone.getBoundingClientRect();
398	      const vh = window.innerHeight;
399	      // Threshold is tuned so the floating button and its static-flow slot
400	      // line up vertically at the moment of switch — the visual position
401	      // doesn't jump.
402	      const phoneEnoughVisible = phoneRect.top < vh - 200;
403	      // The floating button sits at vh - 56 (bottom-6 + button height). The
404	      // static slot sits at phoneRect.bottom + 62 (flex gap-8 + pt-2 + half
405	      // button). The switch happens when the two y positions match.
406	      const phoneStillNearBottom = phoneRect.bottom > vh - 118;
407	      setFloating(phoneEnoughVisible && phoneStillNearBottom);
408	    };
409	
410	    update();
411	    window.addEventListener("scroll", update, { passive: true });
412	    window.addEventListener("resize", update);
413	    return () => {
414	      window.removeEventListener("scroll", update);
415	      window.removeEventListener("resize", update);
416	    };
417	  }, [phoneRef]);
418	
419	  return floating;
420	}
421	
422	const TYPING_DELAY_MS = 450;
423	const TYPING_DURATION_MS = 850;
424	
425	function useStaggeredMessages(platform: Platform): ChatMessageItem[] {
426	  const allMessages = platform.demo.messages;
427	  const [visibleCount, setVisibleCount] = useState(1);
428	  const [showTyping, setShowTyping] = useState(false);
429	
430	  useEffect(() => {
431	    setVisibleCount(1);
432	    setShowTyping(false);
433	    if (allMessages.length <= 1) return;
434	
435	    const timers: ReturnType<typeof setTimeout>[] = [];
436	    let elapsed = 0;
437	    for (let i = 1; i < allMessages.length; i++) {
438	      elapsed += TYPING_DELAY_MS;
439	      timers.push(setTimeout(() => setShowTyping(true), elapsed));
440	      elapsed += TYPING_DURATION_MS;
441	      timers.push(
442	        setTimeout(() => {
443	          setShowTyping(false);
444	          setVisibleCount((c) => c + 1);
445	        }, elapsed),
446	      );
447	    }
448	
449	    return () => {
450	      for (const t of timers) clearTimeout(t);
451	    };
452	  }, [allMessages]);
453	
454	  return useMemo(() => {
455	    const real = allMessages.slice(0, visibleCount).map((m, i) => ({
456	      ...m,
457	      id: m.id ?? `msg-${i}`,
458	    }));
459	    if (!showTyping || visibleCount >= allMessages.length) return real;
460	    const next = allMessages[visibleCount];
461	    return [
462	      ...real,
463	      {
464	        id: `typing-${visibleCount}`,
465	        from: next.from,
466	        author: next.author,
467	        avatar: next.avatar,
468	        authorColor: next.authorColor,
469	        typing: true,
470	      },
471	    ];
472	  }, [allMessages, visibleCount, showTyping]);
473	}
