500	            onClick={() => onSelect(p.id)}
501	            className="cursor-pointer select-none"
502	            startContent={
503	              typeof p.icon === "string" ? (
504	                <Image
505	                  src={p.icon}
506	                  alt=""
507	                  width={20}
508	                  height={20}
509	                  className="h-5 w-5 shrink-0 rounded"
510	                  aria-hidden
511	                />
512	              ) : (
513	                <span
514	                  className="flex h-5 w-5 shrink-0 items-center justify-center"
515	                  aria-hidden
516	                >
517	                  {p.icon}
518	                </span>
519	              )
520	            }
521	          >
522	            {p.name}
523	          </Chip>
524	        );
525	      })}
526	    </div>
527	  );
528	}
529	
530	function PhoneFrame({
531	  platform,
532	  messages,
533	}: {
