538	    <div className="relative isolate">
539	      <div
540	        aria-hidden
541	        className="-z-10 pointer-events-none absolute -inset-x-[28rem] -inset-y-[20rem]"
542	        style={{
543	          backgroundImage:
544	            "radial-gradient(closest-side, rgba(0,187,255,0.7), rgba(0,187,255,0.25) 35%, rgba(0,187,255,0.06) 65%, transparent 80%)",
545	          filter: "blur(18px)",
546	        }}
547	      />
548	      <IPhoneMockup
549	        screenBackground={platform.phone.screenBackground}
550	        statusBarTone={platform.phone.statusBarTone}
551	      >
552	        <AnimatePresence mode="wait" initial={false}>
553	          <m.div
554	            key={platform.id}
555	            className="flex h-full flex-col"
556	            initial={{ opacity: 0, y: 8 }}
557	            animate={{ opacity: 1, y: 0 }}
558	            exit={{ opacity: 0, y: -8 }}
559	            transition={{ duration: 0.2, ease: "easeOut" }}
560	          >
561	            <ChatDemo
562	              platform={platform.id}
563	              title={platform.demo.title}
564	              subtitle={platform.demo.subtitle}
565	              messages={messages}
566	            />
567	          </m.div>
568	        </AnimatePresence>
569	      </IPhoneMockup>
570	    </div>
