573	
574	function PrimaryCTA({
575	  action,
576	  iconSrc,
577	  comingSoon,
578	}: {
579	  action: ActionLink;
580	  iconSrc: string | undefined;
581	  comingSoon?: boolean;
582	}) {
583	  if (comingSoon) {
584	    return (
585	      <RaisedButton
586	        color="#52525B"
587	        className="h-10 cursor-not-allowed rounded-full pr-4 pl-3 before:rounded-full"
588	        tabIndex={-1}
589	        aria-disabled="true"
590	        onClick={(e) => e.preventDefault()}
591	      >
592	        <span className="flex items-center gap-2">
593	          <SquareLockIcon size={18} />
594	          Coming Soon
595	        </span>
596	      </RaisedButton>
597	    );
598	  }
599	
600	  const button = (
601	    <RaisedButton
602	      color="#00bbff"
603	      className="text-black! h-10 rounded-full pr-4 pl-1.5 before:rounded-full"
604	    >
605	      <span className="flex items-center gap-2">
606	        {iconSrc && (
607	          <Image
608	            src={iconSrc}
609	            alt=""
610	            width={28}
611	            height={28}
612	            aria-hidden
613	            className="h-7 w-7 shrink-0 rounded"
614	          />
615	        )}
616	        {action.label}
617	        <CircleArrowRight02Icon size={18} />
618	      </span>
619	    </RaisedButton>
620	  );
621	
622	  if (action.external) {
623	    return (
624	      <a href={action.href} target="_blank" rel="noreferrer">
625	        {button}
626	      </a>
627	    );
628	  }
629	
630	  return <Link href={action.href}>{button}</Link>;
631	}
